// No aplica meta diaria\n        case .sleep: return 8\n        case .weight: return 0 // Meta personalizada\n        }\n    }\n}\n\nstruct HealthMetric: Identifiable, Codable {\n    let id: UUID\n    let type: MetricType\n    let value: Double\n    let date: Date\n    \n    init(id: UUID = UUID(), type: MetricType, value: Double, date: Date = .now) {\n        self.id = id\n        self.type = type\n        self.value = value\n        self.date = date\n    }\n}\n\nstruct DailyLog: Identifiable, Codable {\n    let id: UUID\n    let date: Date\n    var metrics: [HealthMetric]\n    var notes: String\n    \n    init(id: UUID = UUID(), date: Date = .now, metrics: [HealthMetric] = [], notes: String = "") {\n        self.id = id\n        self.date = date\n        self.metrics = metrics\n        self.notes = notes\n    }\n    \n    var stepsCount: Double? {\n        metrics.first(where: { $0.type == .steps })?.value\n    }\n    \n    var heartRate: Double? {\n        metrics.first(where: { $0.type == .heartRate })?.value\n    }\n    \n    var sleepHours: Double? {\n        metrics.first(where: { $0.type == .sleep })?.value\n    }\n}\n\nstruct UserProfile: Codable {\n    var name: String\n    var age: Int\n    var heightCm: Double\n    var targetWeight: Double?\n    var dailyStepsGoal: Double\n    var dailySleepGoal: Double\n    \n    static let `default` = UserProfile(\n        name: "",\n        age: 25,\n        heightCm: 170,\n        targetWeight: nil,\n        dailyStepsGoal: 10_000,\n        dailySleepGoal: 8\n    )\n}\n'})}),"\n",(0,r.jsx)(t.hr,{}),"\n",(0,r.jsx)(t.h2,{id:"paso-2-integrar-healthkit",children:"Paso 2: Integrar HealthKit"}),"\n",(0,r.jsxs)(t.p,{children:["HealthKit es el framework de Apple que permite leer y escribir datos de salud del usuario. ",(0,r.jsx)(t.strong,{children:"Es fundamental solicitar permisos de forma transparente y respetuosa"})," \u2014 algo que los usuarios latinoamericanos valoran especialmente dada la creciente conciencia sobre p